<p>Built by <a href="https://github.com/acunningham-ship-it" target="_blank">Armani</a> | <a href="https://crazeemedia.app.n8n.cloud/webhook/ai-tools">More AI Tools</a> | <a href="https://payhip.com/ArmanisDevTools" target="_blank">Premium Templates</a></p>
</div>
</div>
<script>
function setExample(text){document.getElementById('desc').value=text}
async function generate(){
const desc=document.getElementById('desc').value.trim();
if(!desc){alert('Please describe what you want to match.');return}
const lang=document.getElementById('lang').value;
const usecase=document.getElementById('usecase').value;
const btn=document.getElementById('genBtn');
const loading=document.getElementById('loading');
const result=document.getElementById('result');
btn.disabled=true;btn.textContent='Generating...';
loading.style.display='block';result.style.display='none';
try{
const resp=await fetch('https://crazeemedia.app.n8n.cloud/webhook/regex-api',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({description:desc,language:lang,usecase:usecase})});
const data=await resp.json();
const output=data.regex||data.output||data.result||JSON.stringify(data);
result.innerHTML=formatResult(output);
result.style.display='block';
}catch(e){result.innerHTML='<p style="color:#f5576c">Error: '+e.message+'</p>';result.style.display='block'}
finally{btn.disabled=false;btn.textContent='Generate Regex';loading.style.display='none'}
}
function formatResult(text){
let html='<h3>Your Generated Regex</h3>';
const patternMatch=text.match(/```[^\n]*\n([^`]+)```/);
const mainPattern=patternMatch?patternMatch[1].trim():null;
if(mainPattern){
html+='<div class="regex-box"><button class="copy-btn" onclick="copyRegex(this)">Copy</button>'+escapeHtml(mainPattern)+'</div>';
}
const formatted=text
.replace(/```[^\n]*\n([^`]+)```/g,'<div style="background:#0d1117;border-radius:8px;padding:10px 14px;margin:8px 0;font-family:monospace;font-size:0.88em;color:#96c93d;white-space:pre-wrap">$1</div>')
.replace(/\*\*([^*]+)\*\*/g,'<strong style="color:#fff">$1</strong>')
.replace(/`([^`]+)`/g,'<code style="color:#96c93d;background:rgba(0,176,155,0.1);padding:1px 5px;border-radius:3px;font-family:monospace">$1</code>')
.replace(/^### (.+)$/gm,'<h4 style="color:#00b09b;margin:12px 0 6px">$1</h4>')
.replace(/^## (.+)$/gm,'<h3 style="color:#00b09b;margin:15px 0 8px">$1</h3>')
.replace(/\n/g,'<br>');
html+='<div class="section">'+formatted+'</div>';
return html;
}
function escapeHtml(t){const d=document.createElement('div');d.textContent=t;return d.innerHTML}
function copyRegex(btn){const text=btn.parentElement.textContent.replace('Copy','').trim();navigator.clipboard.writeText(text).then(()=>{btn.textContent='Copied!';setTimeout(()=>btn.textContent='Copy',2000)}).catch(()=>{const ta=document.createElement('textarea');ta.value=text;document.body.appendChild(ta);ta.select();document.execCommand('copy');document.body.removeChild(ta);btn.textContent='Copied!';setTimeout(()=>btn.textContent='Copy',2000)})}
</script>
</body>
</html>

